import { getBrushHandle, setCustomBrushHandle } from '../../visual-effects/brush-handles/handles';
import { propertiesToStyles } from '../../../mark/dom-paint';
import { defined } from '../../../utils/zcutils';
import { getHandleData } from '../../../legend/size-legend/slider/size-slider-helpers';
import { getDisabledOptions, getHoverOptions } from '../../../legend/events/legend-event-helpers';

export function getHandles(behaviour) {
    let behaviourInstance = behaviour.instance,
        { component, extent } = behaviourInstance.options,
        { brushOptions } = component,
        { type, config, markerBound, handles: handleOptions } = brushOptions,
        { width, height } = markerBound,
        data = getHandleData(brushOptions),
        filterConfig = getDisabledOptions(config),
        hoverOptions = getHoverOptions(config),
        markerConfig = config.slider.marker,
        handleType = filterConfig.type,
        handleSymbol = markerConfig.shape || 'circle';

    if (handleType) {
        return getBrushHandle(type, handleType, extent, null, filterConfig[handleType] || {});
    } else {
        let transform = handleOptions.transform,
            symbolPath = handleOptions.shape,
            _path = d => symbolPath(width(d), height(d)),
            op = {
                shape: defined(hoverOptions.type)
                    ? [[_path(data[0]), _path(data[0])], [_path(data[1]), _path(data[1])]]
                    : [[_path(data[0])], [_path(data[1])]],
                style: {
                    ...propertiesToStyles(markerConfig),
                    transform: d => transform(data[d.i])
                }
            };

        setCustomBrushHandle(`marker-${handleSymbol}`, op);
        return getBrushHandle(type, `marker-${handleSymbol}`, extent, null, markerConfig);
    }
}
